#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
#define Sum(l,r) (s[r]^s[(l)-1])
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline void CV(vector<T> &v){vector<T> t;v.swap(t);}
const int N=505;
int qx[N][N],qy[N][N];
typedef unsigned long long ull;
typedef unsigned ui;
ui seed=998244353;inline ui rnd(){seed^=seed<<19;seed^=seed>>13;seed^=seed<<7;return seed;}
struct Bitset
{
	ull a[8];inline void ins(int x){a[x>>6]|=1ull<<(x&63);}
	inline bool operator [] (int x){return a[x>>6]>>(x&63)&1;}
	inline void clear(){memset(a,0,sizeof(a));}
	inline void OR(Bitset &x)
	{
		a[0]|=x.a[0];a[1]|=x.a[1];a[2]|=x.a[2];a[3]|=x.a[3];
		a[4]|=x.a[4];a[5]|=x.a[5];a[6]|=x.a[6];a[7]|=x.a[7];
	}
}g[N][N];
int n,a[N],s[N],cnt;
vector<int> bac[N],frw[N];
struct tpl{int x,y,z;}stk[N];int top;
inline void dfs(int p,int l,int r)
{
	
	if(l==r)return;int x=qx[l][r],y=qy[l][r],w=Sum(l,x)^Sum(y,r);
	int bl=x+1,br=y-1,mid;while(bl<=br)g[mid=(bl+br)>>1][y-1][w]?bl=mid+1:br=mid-1;int i=bl-1;
	bl=i;br=y-1;while(bl<=br)g[i][mid=(bl+br)>>1][w]?br=mid-1:bl=mid+1;int j=br+1;
//	printf("dfs (%d,%d,%d) :: %d %d %d %d\n",p,l,r,x,i,j,y);
	dfs(p,l,x);dfs(p+i-x,i,j);dfs(p+i-x+y-j,y,r);stk[++top]={p,p+i-x,p+i-x+y-j};
}
inline void Solve()
{
	n=read();rep(1,n,i)s[i]=s[i-1]^(a[i]=read());
	rep(1,n,l)rep(l,n,r)g[l][r].clear(),qx[l][r]=0;
	rep(1,n,i)
	{
		g[i][i].ins(a[i]);if(i!=n)g[i][i+1].ins(a[i]);
		if(i!=1)g[i-1][i].ins(a[i]);qx[i][i]=qy[i][i]=i;
		CV(frw[i]);CV(bac[i]);frw[i].push_back(i);bac[i].push_back(i);
	}
	rep(3,n,T)for(int l=1,r=T;r<=n;++l,++r)
	{
		bool flag=false;int cnt=0;
		for(int x:frw[l])
		{
			for(int y:bac[r])
			{
				if(y<=x+1)break;
				if(g[x+1][y-1][Sum(l,x)^Sum(y,r)])
				{
					qx[l][r]=x;
					qy[l][r]=y;
					flag=true;
					break;
				}
				if((++cnt)>(r-l+1)*3)break;
			}
			if(cnt>(r-l+1)*3)break;
			if(flag)break;
		}
		g[l][r].OR(g[l+1][r]);g[l][r].OR(g[l][r-1]);
		if(flag)
		{
			g[l][r].ins(Sum(l,r));
			frw[l].push_back(r);
			bac[r].push_back(l);
		}
	}
	puts(qx[1][n]?"Huoyu":"Shuiniao");if(!qx[1][n])return;
	dfs(1,1,n);printf("%d\n",top);
	rep(1,top,i)printf("%d %d %d\n",stk[i].x,stk[i].y,stk[i].z);top=0;
	
}
int main(){int T=read();while(T--)Solve();}
